+    for (const target of to) {
+      if (target === '*') {
+        // Broadcast to all (except sender)
+        recipients.push(
+          ...Array.from(this.state.agents.keys())
+            .filter(id => id !== message.from)
+        );
+      } else {
+        recipients.push(target);
+      }
+    }
