+  /**
+   * Update message statistics
+   */
+  private updateMessageStats(agentId: string, type: 'sent' | 'received', latency: number): void {
+    const stats = this.messageStats.get(agentId);
+    if (!stats) {
+      return;
+    }
+
+    if (type === 'sent') {
+      stats.sent++;
+    } else {
+      stats.received++;
+    }
+
+    stats.latency.push(latency);
+
+    // Keep only last 100 latency measurements
+    if (stats.latency.length > 100) {
+      stats.latency.shift();
+    }
+  }
+
+  /**
+   * Calculate current swarm statistics
+   */
+  private async calculateStats(): Promise<SwarmStats> {
+    const quicStats = await this.config.quicClient.getStats();
