+      }
+    }
+    const averageLatency = latencyCount > 0 ? totalLatency / latencyCount : 0;
+
+    return {
+      totalAgents: this.state.agents.size,
+      activeAgents: this.state.agents.size,
+      totalMessages: this.state.stats.totalMessages,
+      messagesPerSecond,
+      averageLatency,
+      quicStats
+    };
+  }
+}

